{
  "name": "open-generative-ai",
  "description": "Open-source alternative to HF AI — AI image, video, cinema and lip sync studio",
  "homepage": "https://github.com/Anil-matcha/Open-Generative-AI",
  "private": true,
  "version": "2.0.0",
  "license": "MIT",
  "workspaces": [
    "packages/studio",
    "packages/Vibe-Workflow/packages/workflow-builder",
    "packages/Open-Poe-AI/packages/agents",
    "packages/Open-AI-Design-Agent/packages/design-agent"
  ],
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "lint": "next lint",
    "build:studio": "npm run build -w studio",
    "build:workflow": "npm run build -w workflow-builder",
    "build:agent": "npm run build -w ai-agent",
    "build:packages": "npm run build:workflow && npm run build:agent && npm run build:studio",
    "setup": "git submodule update --init --recursive && npm install && npm run build:packages",
    "vite:dev": "vite",
    "vite:build": "vite build",
    "electron:dev": "npm run vite:build && electron .",
    "electron:build": "vite build && electron-builder --mac",
    "electron:build:win": "vite build && electron-builder --win",
    "electron:build:linux": "vite build && electron-builder --linux",
    "electron:build:linux:dir": "vite build && electron-builder --linux dir",
    "electron:build:linux:arm64:dir": "vite build && electron-builder --linux dir --arm64",
    "stage:local-ai": "node scripts/stage-local-ai-binary.js",
    "package:linux:deb": "node scripts/package-linux-deb.js",
    "package:linux:deb:arm64": "node scripts/package-linux-deb.js --arch arm64",
    "package:linux:deb:x64": "node scripts/package-linux-deb.js --arch x64",
    "electron:build:all": "vite build && electron-builder --mac --win --linux"
  },
  "build": {
    "appId": "ai.generative.open",
    "productName": "Open Generative AI",
    "copyright": "Copyright © 2025",
    "directories": {
      "output": "release"
    },
    "afterPack": "./afterPack.js",
    "files": [
      "dist/**/*",
      "electron/**/*"
    ],
    "extraResources": [
      {
        "from": "build/local-ai",
        "to": "local-ai",
        "filter": [
          "**/*"
        ]
      }
    ],
    "mac": {
      "category": "public.app-category.graphics-design",
      "icon": "public/banner.png",
      "gatekeeperAssess": false,
      "target": [
        {
          "target": "dmg",
          "arch": [
            "x64",
            "arm64"
          ]
        }
      ]
    },
    "win": {
      "icon": "public/banner.png",
      "signAndEditExecutable": false,
      "target": [
        {
          "target": "nsis",
          "arch": [
            "x64"
          ]
        }
      ]
    },
    "nsis": {
      "oneClick": false,
      "allowToChangeInstallationDirectory": true,
      "include": "build/installer.nsh"
    },
    "linux": {
      "icon": "public/banner.png",
      "category": "Utility",
      "maintainer": "Open Generative AI Team",
      "extraFiles": [
        {
          "from": "build/linux/apparmor.profile",
          "to": "resources/apparmor.profile"
        }
      ],
      "target": [
        {
          "target": "AppImage",
          "arch": [
            "x64"
          ]
        },
        {
          "target": "deb",
          "arch": [
            "x64"
          ]
        }
      ]
    }
  },
  "dependencies": {
    "axios": "^1.7.0",
    "next": "^15.0.0",
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "react-hot-toast": "^2.4.1",
    "studio": "*",
    "workflow-builder": "file:./packages/Vibe-Workflow/packages/workflow-builder",
    "ai-agent": "file:./packages/Open-Poe-AI/packages/agents"
  },
  "devDependencies": {
    "@eslint/eslintrc": "^3",
    "@tailwindcss/vite": "^4.1.18",
    "autoprefixer": "^10.4.24",
    "electron": "^33.4.11",
    "electron-builder": "^25.1.8",
    "eslint": "^9",
    "eslint-config-next": "^15.0.0",
    "postcss": "^8.5.6",
    "tailwindcss": "^3.4.0",
    "vite": "^5.4.0"
  },
  "main": "electron/main.js"
}

{
  "name": "fastify",
  "version": "5.9.0",
  "description": "Fast and low overhead web framework, for Node.js",
  "main": "fastify.js",
  "type": "commonjs",
  "types": "fastify.d.ts",
  "scripts": {
    "bench": "branchcmp -r 2 -g -s \"npm run benchmark\"",
    "benchmark": "concurrently -k -s first \"node ./examples/benchmark/simple.js\" \"autocannon -c 100 -d 30 -p 10 localhost:3000/\"",
    "benchmark:parser": "concurrently -k -s first \"node ./examples/benchmark/parser.js\" \"autocannon -c 100 -d 30 -p 10 -i ./examples/benchmark/body.json -H \"content-type:application/jsoff\" -m POST localhost:3000/\"",
    "benchmark:parser:error": "concurrently -k -s first \"node ./examples/benchmark/parser.js\" \"autocannon -c 100 -d 30 -p 10 -i ./examples/benchmark/body.json -H \"content-type:application/jsoff\" -H \"content-length:123\" -m POST localhost:3000/\"",
    "build:validation": "node build/build-error-serializer.js && node build/build-validation.js",
    "build:sync-version": "node build/sync-version.js",
    "coverage": "c8 --reporter html borp --reporter=@jsumners/line-reporter",
    "coverage:ci-check-coverage": "borp --reporter=@jsumners/line-reporter --coverage --check-coverage --lines 100",
    "lint": "npm run lint:eslint",
    "lint:fix": "eslint --fix",
    "lint:markdown": "markdownlint-cli2",
    "lint:eslint": "eslint",
    "prepublishOnly": "cross-env PREPUBLISH=true borp --reporter=@jsumners/line-reporter && npm run test:validator:integrity && npm run build:sync-version",
    "test": "npm run lint && npm run unit && npm run test:types",
    "test:ci": "npm run unit && npm run test:types",
    "test:report": "npm run lint && npm run unit:report && npm run test:types",
    "test:validator:integrity": "npm run build:validation && git diff --quiet --ignore-all-space --ignore-blank-lines --ignore-cr-at-eol lib/error-serializer.js && git diff --quiet --ignore-all-space --ignore-blank-lines --ignore-cr-at-eol lib/config-validator.js",
    "test:types": "tstyche",
    "test:watch": "npm run unit -- --watch --coverage-report=none --reporter=terse",
    "unit": "borp",
    "unit:report": "c8 --reporter html borp --reporter=@jsumners/line-reporter",
    "citgm": "borp --reporter=@jsumners/line-reporter --coverage --check-coverage --concurrency=1"
  },
  "repository": {
    "type": "git",
    "url": "git+https://github.com/fastify/fastify.git"
  },
  "keywords": [
    "web",
    "framework",
    "json",
    "schema",
    "open",
    "api"
  ],
